import UIKit

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    
    private enum LinkRoute {
        case profile(userId: String)
        case paymentConfirm
        case adminSettings
        case unknown
    }
    
    private init() {}
    
    func handleUniversalLink(_ url: URL, completion: @escaping (Bool) -> Void) {
        guard validateHost(url) else {
            print("Invalid host: \(url.host ?? "unknown")")
            completion(false)
            return
        }
        
        let route = parseRoute(from: url)
        
        switch route {
        case .profile(let userId):
            handleProfileRoute(userId: userId, completion: completion)
        case .paymentConfirm:
            handlePaymentConfirmRoute(completion: completion)
        case .adminSettings:
            handleAdminSettingsRoute(completion: completion)
        case .unknown:
            print("Unknown route: \(url.path)")
            completion(false)
        }
    }
    
    private func validateHost(_ url: URL) -> Bool {
        guard let scheme = url.scheme, scheme == "https" else {
            return false
        }
        
        guard let host = url.host?.lowercased() else {
            return false
        }
        
        return allowedHosts.contains(host)
    }
    
    private func parseRoute(from url: URL) -> LinkRoute {
        let pathComponents = url.pathComponents.filter { $0 != "/" }
        
        guard !pathComponents.isEmpty else {
            return .unknown
        }
        
        switch pathComponents[0] {
        case "profile":
            if pathComponents.count == 2 {
                let userId = pathComponents[1]
                if isValidUserId(userId) {
                    return .profile(userId: userId)
                }
            }
        case "payment":
            if pathComponents.count == 2 && pathComponents[1] == "confirm" {
                return .paymentConfirm
            }
        case "admin":
            if pathComponents.count == 2 && pathComponents[1] == "settings" {
                return .adminSettings
            }
        default:
            break
        }
        
        return .unknown
    }
    
    private func isValidUserId(_ userId: String) -> Bool {
        let allowedCharacters = CharacterSet.alphanumerics
        let userIdCharacterSet = CharacterSet(charactersIn: userId)
        
        guard allowedCharacters.isSuperset(of: userIdCharacterSet) else {
            return false
        }
        
        guard userId.count > 0 && userId.count <= 50 else {
            return false
        }
        
        return true
    }
    
    private func handleProfileRoute(userId: String, completion: @escaping (Bool) -> Void) {
        guard let currentUserId = AuthenticationManager.shared.getCurrentUserId() else {
            print("User not authenticated")
            completion(false)
            return
        }
        
        if userId != currentUserId {
            AuthorizationManager.shared.canViewProfile(userId: userId) { authorized in
                if authorized {
                    DispatchQueue.main.async {
                        self.navigateToProfile(userId: userId)
                        completion(true)
                    }
                } else {
                    print("User not authorized to view profile: \(userId)")
                    completion(false)
                }
            }
        } else {
            DispatchQueue.main.async {
                self.navigateToProfile(userId: userId)
                completion(true)
            }
        }
    }
    
    private func handlePaymentConfirmRoute(completion: @escaping (Bool) -> Void) {
        guard AuthenticationManager.shared.isAuthenticated() else {
            print("User not authenticated for payment confirmation")
            completion(false)
            return
        }
        
        DispatchQueue.main.async {
            self.navigateToPaymentConfirm()
            completion(true)
        }
    }
    
    private func handleAdminSettingsRoute(completion: @escaping (Bool) -> Void) {
        guard AuthenticationManager.shared.isAuthenticated() else {
            print("User not authenticated for admin settings")
            completion(false)
            return
        }
        
        AuthorizationManager.shared.isAdmin { isAdmin in
            if isAdmin {
                DispatchQueue.main.async {
                    self.navigateToAdminSettings()
                    completion(true)
                }
            } else {
                print("User not authorized to access admin settings")
                completion(false)
            }
        }
    }
    
    private func navigateToProfile(userId: String) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let profileVC = ProfileViewController()
        profileVC.userId = userId
        
        if let navController = rootViewController as? UINavigationController {
            navController.pushViewController(profileVC, animated: true)
        } else if let tabBarController = rootViewController as? UITabBarController,
                  let navController = tabBarController.selectedViewController as? UINavigationController {
            navController.pushViewController(profileVC, animated: true)
        } else {
            let navController = UINavigationController(rootViewController: profileVC)
            rootViewController.present(navController, animated: true)
        }
    }
    
    private func navigateToPaymentConfirm() {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let paymentVC = PaymentConfirmViewController()
        
        if let navController = rootViewController as? UINavigationController {
            navController.pushViewController(paymentVC, animated: true)
        } else if let tabBarController = rootViewController as? UITabBarController,
                  let navController = tabBarController.selectedViewController as? UINavigationController {
            navController.pushViewController(paymentVC, animated: true)
        } else {
            let navController = UINavigationController(rootViewController: paymentVC)
            rootViewController.present(navController, animated: true)
        }
    }
    
    private func navigateToAdminSettings() {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let adminVC = AdminSettingsViewController()
        
        if let navController = rootViewController as? UINavigationController {
            navController.pushViewController(adminVC, animated: true)
        } else if let tabBarController = rootViewController as? UITabBarController,
                  let navController = tabBarController.selectedViewController as? UINavigationController {
            navController.pushViewController(adminVC, animated: true)
        } else {
            let navController = UINavigationController(rootViewController: adminVC)
            rootViewController.present(navController, animated: true)
        }
    }
}

class AuthenticationManager {
    static let shared = AuthenticationManager()
    
    private var currentUserId: String?
    private var authenticated: Bool = false
    
    private init() {}
    
    func isAuthenticated() -> Bool {
        return authenticated
    }
    
    func getCurrentUserId() -> String? {
        return authenticated ? currentUserId : nil
    }
    
    func setAuthenticated(userId: String) {
        self.authenticated = true
        self.currentUserId = userId
    }
    
    func logout() {
        self.authenticated = false
        self.currentUserId = nil
    }
}

class AuthorizationManager {
    static let shared = AuthorizationManager()
    
    private var adminUsers: Set<String> = []
    
    private init() {}
    
    func canViewProfile(userId: String, completion: @escaping (Bool) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.1) {
            completion(true)
        }
    }
    
    func isAdmin(completion: @escaping (Bool) -> Void) {
        guard let currentUserId = AuthenticationManager.shared.getCurrentUserId() else {
            completion(false)
            return
        }
        
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.1) {
            let isAdmin = self.adminUsers.contains(currentUserId)
            completion(isAdmin)
        }
    }
    
    func setAdminUser(userId: String) {
        adminUsers.insert(userId)
    }
}

class ProfileViewController: UIViewController {
